```javascript
function stripCredentials(url) {
  const parsedUrl = new URL(url);
  const { protocol, hostname, pathname, search, hash } = parsedUrl;

  // Remove username and password from the hostname
  const strippedHostname = hostname.replace(/^([^:]+):([^:]+)(:.*)?$/, '$1$3');

  // Reconstruct the URL without username and password
  const strippedUrl = `${protocol}://${strippedHostname}${pathname}${search}${hash}`;

  return strippedUrl;
}

