You can create a custom middleware to handle proxy requests. This approach is useful when you want to proxy requests for multiple endpoints.

```csharp
public class ProxyMiddleware
{
    private readonly RequestDelegate _next;
    private readonly string _targetUrl;

    public ProxyMiddleware(RequestDelegate next, string targetUrl)
    {
        _next = next;
        _targetUrl = targetUrl;
    }

    public async Task InvokeAsync(HttpContext context)
    {
        var originalUrl = context.Request.Path;
        var proxyUrl = _targetUrl + originalUrl;

        context.Request.Path = proxyUrl;
        context.Request.Scheme = _targetUrl.StartsWith("http://") ? "http" : "https";
        context.Request.Host = new HostString(_targetUrl);

        await _next(context);
    }
}
```

